        return s

    result = []
    start_index = -1
    end_index = -1

    # Find first occurrence
    for i, c in enumerate(s):
        if c == char:
            if start_index == -1:
                start_index = i
            break

    # Find last occurrence
    for i in range(len(s) - 1, -1, -1):
        if s[i] == char:
            end_index = i
            break

    # If char not found, return original string
    if start_index == -1:
        return s

    # Remove first and last occurrence
    # If first and last are the same (only one occurrence), remove just one
    if start_index == end_index:
        return s[:start_index] + s[start_index+1:]
    else:
        return s[:start_index] + s[start_index+1:end_index] + s[end_index+1:]

