def is_octagonal(n):
    if n <= 0:
        return False
    discriminant = 8 * n - 7
    if discriminant < 1:
        return False
    sqrt_discriminant = discriminant ** 0.5
    if sqrt_discriminant != int(sqrt_discriminant):
        return False
    k = (1 + int(sqrt_discriminant)) // 2
    if k <= 0:
        return False
    octagonal_number = k * (6 * k - 4) // 2
    return octagonal_number == n

