def bell_number_recursive(n):
    memo = {}

    def helper(k):
        if k in memo:
            return memo[k]
        if k == 0:
            memo[k] = 1
            return 1

        total = 0
        for j in range(k):
            total += helper(j) * bell_number_recursive(k - j - 1)
        memo[k] = total
        return total

    return helper(n)

