def closest_num(n):
    """
    Returns the closest smaller number than n.
    For integer input, returns n - 1.
    For float input, returns the largest float less than n.
    """
    if isinstance(n, int):
        return n - 1
    else:
        # For floats, return n - epsilon
        import math
        return n - math.nextafter(n, -math.inf)

