def is_undulating(n):
    """
    Check if the number is undulating.
    A number is undulating if its digits alternate between increasing and decreasing.
    For example: 1212121 -> 1<2>1<2>1<2>1 (alternating)
    """
    s = str(n)
    if len(s) < 2:
        return False

    # Check if the first two digits are equal (not undulating)
    if s[0] == s[1]:
        return False

    increasing = (s[1] > s[0])

    for i in range(2, len(s)):
        current = s[i]
        prev = s[i-1]

        if current == prev:
            return False

        if increasing:
            if current <= prev:
                return False
        else:
            if current >= prev:
                return False

        increasing = not increasing

    return True

