def is_undulating(n):
    """
    Check if the number is undulating.
    An undulating number is a number that alternates between increasing and decreasing digits.
    For example, 1212121 is undulating because it goes up, down, up, down, etc.
    """
    s = str(n)
    if len(s) < 2:
        return False

    # Check if the first two digits are different
    if s[0] == s[1]:
        return False

    # Check alternation
    for i in range(1, len(s)):
        prev_digit = int(s[i-1])
        curr_digit = int(s[i])

        # Determine the direction from the previous comparison
        if i == 1:
            direction = 1 if curr_digit > prev_digit else -1
        else:
            expected_direction = -direction if i % 2 == 1 else direction

            if curr_digit > prev_digit:
                expected_direction = 1
            else:
                expected_direction = -1

            if expected_direction != direction:
                return False
            direction = expected_direction

    return True

