def next_smallest_palindrome(n):
    def is_palindrome(x):
        s = str(x)
        return s == s[::-1]

    def next_palindrome(x):
        if x < 0:
            return -x
        if x == 0:
            return 0

        s = str(x)
        length = len(s)

        # Check if current number is palindrome
        if is_palindrome(x):
            # Find next palindrome
            next_s = s[1:] + '1' + s[:1]
            return int(next_s)

        # Try to find next palindrome by mirroring
        half = s[:length//2]
        if length % 2 == 1:
            half += s[length//2]

        # Try mirroring
        mirror = half + half[::-1]
        if int(mirror) > x:
            return int(mirror)

        # If mirror is not greater, increment half and mirror again
        half = str(int(half) + 1)
        if length % 2 == 1:
            half += s[length//2]

        mirror = half + half[::-1]
        return int(mirror)

    return next_palindrome(n)

