def eulerian_num(n, m):
    if m < 0 or m > n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0

    # A(n, m) = (m+1)*A(n-1, m) + n*A(n-1, m-1)
    # Base case: A(0, 0) = 1
    dp = [0] * (n + 1)
    dp[0] = 1

    for i in range(1, n + 1):
        new_dp = [0] * (i + 1)
        for j in range(i + 1):
            if j == 0:
                new_dp[j] = 1  # A(i, 0) = 1 for i >= 0
            else:
                new_dp[j] = (j + 1) * dp[j] + i * dp[j - 1]
        dp = new_dp

    return dp[m]

