def odd_Equivalent(s, n):
    def count_ones(current):
        return sum(int(c) for c in current)

    if n == 0:
        return count_ones(s)

    length = len(s)
    effective_n = n % length

    if effective_n == 0:
        return count_ones(s)

    # Simulate the rotation
    rotated = s[-effective_n:] + s[:-effective_n]
    return count_ones(rotated)

