    Find the element that appears only once in a sorted array.

    Args:
        nums (List[int]): A sorted list of integers where exactly one element appears once.

    Returns:
        int: The unique element.
    """
    left, right = 0, len(nums) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is at the boundary of the unique element
        if mid % 2 == 0:
            if nums[mid] == nums[mid + 1]:
                left = mid + 1
            else:
                right = mid
        else:
            if nums[mid] == nums[mid - 1]:
                left = mid + 1
            else:
                right = mid - 1

    return nums[left]

