def search(arr):
    """
    Find the element that appears only once in a sorted array.
    """
    n = len(arr)
    if n == 0:
        return None

    # Binary search approach
    left, right = 0, n - 1

    while left <= right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        # If mid is the unique element, then:
        # - The element at mid-1 (if exists) should be less than mid
        # - The element at mid+1 (if exists) should be greater than mid
        # - The element at mid-1 should be equal to mid-2 (if exists)
        # - The element at mid+1 should be equal to mid+2 (if exists)

        if mid == 0:
            if mid + 1 < n and arr[mid] != arr[mid + 1]:
                return arr[mid]
            else:
                left = mid + 1
        elif mid == n - 1:
            if mid - 1 >= 0 and arr[mid] != arr[mid - 1]:
                return arr[mid]
            else:
                right = mid - 1
        else:
            # Check left side
            if arr[mid] == arr[mid - 1]:
                # mid and mid-1 are the same, so unique element must be on the right
                left = mid + 1
            elif arr[mid] == arr[mid + 1]:
                # mid and mid+1 are the same, so unique element must be on the left
                right = mid - 1

