def count_char_position(s: str) -> int:
    """
    Count the number of characters in the string that occur at the same position
    in the string as in the English alphabet (case insensitive).

    For example:
    - 'a' is at index 0 in the alphabet and should be counted if it appears at index 0 in the string.
    - 'b' is at index 1 in the alphabet and should be counted if it appears at index 1 in the string.
    - And so on.
    """
    if not s:
        return 0

    count = 0
    for i, char in enumerate(s):
        if 'a' <= char <= 'z':
            if char == chr(ord('a') + i):
                count += 1
        elif 'A' <= char <= 'Z':
            if char == chr(ord('A') + i):
                count += 1

    return count

def count_char_position(s: str) -> int:
    """
    Counts the number of characters in the string that occur at the same position
    in the string as in the English alphabet (case insensitive).

    For example, 'a' is at position 0 in the alphabet and should be at index 0 in the string.
    'b' is at position 1 in the alphabet and should be at index 1 in the string.
    etc.
    """
    if not s:
        return 0

    count = 0
    for i, char in enumerate(s):
        if 'a' <= char <= 'z':
            expected_index = ord(char.lower()) - ord('a')
            if i == expected_index:
                count += 1
        elif 'A' <= char <= 'Z':
            expected_index = ord(char.lower()) - ord('a')
            if i == expected_index:
                count += 1

    return count

