def sum_range_list(numbers, start_index, end_index):
    """
    Calculate the sum of numbers in a list within a specified range of indices.

    Args:
        numbers (list): List of numbers.
        start_index (int): Starting index (inclusive).
        end_index (int): Ending index (inclusive).

    Returns:
        int: Sum of numbers within the specified range.
    """
    if not isinstance(numbers, list):
        raise TypeError("The first argument must be a list.")
    if not isinstance(start_index, int) or not isinstance(end_index, int):
        raise TypeError("Indices must be integers.")
    if start_index < 0 or end_index >= len(numbers):
        raise IndexError("Indices are out of range.")
    if start_index > end_index:
        raise ValueError("Start index must be less than or equal to end index.")

    return sum(numbers[i] for i in range(start_index, end_index + 1))

