def combinations_colors(lst, n):
    result = []
    def backtrack(start, path):
        if len(path) == n:
            result.append(tuple(path))
            return
        for i in range(start, len(lst)):
            backtrack(i, path + [lst[i]])
    backtrack(0, [])
    return result

def combinations_colors(lst, n):
    def generate(index, current, result):
        if len(current) == n:
            result.append(tuple(current))
            return
        for i in range(len(lst)):
            current.append(lst[i])
            generate(index + 1, current, result)
            current.pop()

    result = []
    generate(0, [], result)
    return result

