def combinations_colors(lst, n):
    result = []
    def helper(start, current):
        if len(current) == n:
            result.append(tuple(current))
            return
        for i in range(start, len(lst)):
            helper(i, current + [lst[i]])
    helper(0, [])
    return result

def combinations_colors(colors, n):
    result = []
    def generate(current, index):
        if len(current) == n:
            result.append(tuple(current))
            return
        for i in range(len(colors)):
            current.append(colors[i])
            generate(current, index + 1)
            current.pop()
    generate([], 0)
    return result

def combinations_colors(colors, n):
    def backtrack(start, current, length):
        if length == 0:
            yield tuple(current)
            return

        for i in range(start, len(colors)):
            current.append(colors[i])
            backtrack(i, current, length - 1)
            current.pop()

    yield from backtrack(0, [], n)

