def combinations_colors(elements, length):
    if length == 0:
        return [[]]

    result = []
    def generate(current, remaining_length):
        if remaining_length == 0:
            result.append(current[:])
            return
        for i in range(len(elements)):
            current.append(elements[i])
            generate(current, remaining_length - 1)
            current.pop()

    generate([], length)
    return [tuple(comb) for comb in result]

