def is_newman_prime(n):
    """Check if n is a Newman-Shanks-Williams prime."""
    if n < 2:
        return False
    if n % 2 == 0:
        return False

    # Check divisibility by small primes
    for i in range(3, int(math.sqrt(n)) + 1, 2):
        if n % i == 0:
            return False

    # Check if n is of the form 2^k * 3^m * 5^n - 1
    # Actually, NSW primes are primes of the form 2^k * 3^m * 5^n - 1
    # But more precisely, they are primes of the form 2^k * 3^m * 5^n - 1 where k, m, n are non-negative integers
    # However, the standard definition is that they are primes of the form 2^k * 3^m * 5^n - 1
    # Let's use the property that they are primes of the form 2^k * 3^m * 5^n - 1

    # Check if n is of the form 2^k * 3^m * 5^n - 1
    # This is equivalent to checking if n + 1 is of the form 2^k * 3^m * 5^n

    temp = n + 1
    while temp % 2 == 0:
        temp //= 2
    while temp % 3 == 0:
        temp //= 3
    while temp % 5 == 0:
        temp //= 5

    return temp == 1

