    """
    Find the nth Newman-Shanks-Williams (NSW) prime number.

    An NSW prime is a prime number of the form N_k = k^2 + k + 1 where k is also prime.
    The sequence starts: 7, 31, 313, ...
    """
    def is_prime(num):
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        i = 3
        while i * i <= num:
            if num % i == 0:
                return False
            i += 2
        return True

    k = 2
    count = 0
    while True:
        # Calculate NSW number for current prime k
        ns_number = k * k + k + 1

        # Check if the NSW number is prime
        if is_prime(ns_number):
            count += 1
            if count == n:
                return ns_number

        # Move to next prime k
        k += 1
        if k % 2 == 0:
            continue
        if k == 2:
            k += 1
        else:
            k += 2

