def even_binomial_Coeff_Sum(n):
    """
    Calculates the sum of even index binomial coefficients for a given positive integer n.
    The sum of binomial coefficients at even indices (C(n,0) + C(n,2) + C(n,4) + ...) is 2^(n-1) for n > 0.
    """
    if n == 0:
        return 1
    return 2 ** (n - 1)

def even_binomial_Coeff_Sum(n):
    if n < 0:
        raise ValueError("Input must be a non-negative integer")

    def binomial_coeff(n, k):
        if k < 0 or k > n:
            return 0
        if k == 0 or k == n:
            return 1
        if k > n // 2:
            k = n - k

        result = 1
        for i in range(k):
            result = result * (n - i) // (i + 1)
        return result

    total_sum = 0
    for i in range(0, n + 1, 2):
        total_sum += binomial_coeff(n, i)

    return total_sum

def even_binomial_Coeff_Sum(n):
    """
    Computes the sum of binomial coefficients C(n, k) where k is even.
    This sum equals 2^(n-1) for n >= 1.
    """
    if n == 0:
        return 1
    return 2 ** (n - 1)

def even_binomial_Coeff_Sum(n):
    """
    Computes the sum of binomial coefficients at even indices for a given positive integer n.
    That is, computes sum(C(n, k)) for all even k in [0, n].

    This sum equals 2^(n-1) for n >= 1.
    """
    if n <= 0:
        raise ValueError("n must be a positive integer")
    return 2 ** (n - 1)


