def validate(n: int) -> bool:
    """
    Check whether the frequency of each digit in the integer is less than or equal to the digit itself.

    Args:
        n (int): The integer to validate.

    Returns:
        bool: True if the condition is met for all digits, False otherwise.
    """
    if n < 0:
        n = -n  # Handle negative numbers by considering absolute value

    digit_counts = {}

    # Count frequency of each digit
    for digit_char in str(n):
        digit = int(digit_char)
        digit_counts[digit] = digit_counts.get(digit, 0) + 1

    # Check if frequency of each digit is <= the digit itself
    for digit, count in digit_counts.items():
        if count > digit:
            return False

    return True

