def max_sub_array_sum_repeated(arr, k, m):
    def max_sub_array_sum(arr):
        max_so_far = float('-inf')
        current_max = 0
        for num in arr:
            current_max = max(num, current_max + num)
            max_so_far = max(max_so_far, current_max)
        return max_so_far

    def max_sub_array_sum_repeated_k(arr, k):
        n = len(arr)
        total_sum = sum(arr)

        if total_sum <= 0:
            return max_sub_array_sum(arr)

        prefix_sum = [0] * (n + 1)
        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + arr[i]

        suffix_sum = [0] * (n + 1)
        for i in range(n):
            suffix_sum[i] = suffix_sum[i + 1] + arr[i]

        max_prefix = max(prefix_sum[1:])
        max_suffix = max(suffix_sum[:-1])

        max_mid = max_sub_array_sum(arr)

        if k == 1:
            return max_mid

        if k == 2:
            return max(max_prefix + max_suffix, max_mid)

        return max_prefix + total_sum * (k - 2) + max_suffix

    return max_sub_array_sum_repeated_k(arr, k)

