    def max_sub_array_sum_with_repeats(arr, k):
        n = len(arr)
        total_sum = sum(arr)

        if total_sum <= 0:
            # No wrapping beneficial, just Kadane's on original array
            return max_sub_array_sum(arr)

        # Max sum from one full wrap
        max_wrap = total_sum
        # Max prefix sum
        prefix_sum = 0
        max_prefix = arr[0]
        for num in arr:
            prefix_sum += num
            max_prefix = max(max_prefix, prefix_sum)

        # Max suffix sum
        suffix_sum = 0
        max_suffix = arr[-1]
        for i in range(n - 2, -1, -1):
            suffix_sum += arr[i]
            max_suffix = max(max_suffix, suffix_sum)

        # If k >= 3, we can take max_prefix + (k-2)*total_sum + max_suffix
        if k >= 3:
            return max_prefix + (k - 2) * total_sum + max_suffix

        # For k = 1 or k = 2, just compute directly
        if k == 1:
            return max_sub_array_sum(arr)

        # For k = 2: max(prefix + suffix) or just Kadane on concatenated
        if k == 2:
            # Construct concatenated array virtually
            combined = arr + arr
            return max_sub_array_sum(combined)

        return max_sub_array_sum(arr)

    # Special case: if k=0, return 0

def max_sub_array_sum_repeated(arr, k, num):
