        max_sum = current_sum = arr[0]
        for i in range(1, len(arr)):
            current_sum = max(arr[i], current_sum + arr[i])
            max_sum = max(max_sum, current_sum)
        return max_sum

    total_sum = sum(arr)
    max_prefix = 0
    max_suffix = 0
    current_prefix = 0
    current_suffix = 0

    for x in arr:
        current_prefix = max(x, current_prefix + x)
        max_prefix = max(max_prefix, current_prefix)
        current_suffix = max(x, current_suffix + x)
        max_suffix = max(max_suffix, current_suffix)

    if total_sum <= 0:
        return max(max_sub_array_sum(arr), max_prefix + max_suffix)
    else:
        return max(
            max_sub_array_sum(arr),
            max_prefix + max_suffix + (k - 2) * total_sum
        )

