def get_Inv_Count(arr):
    def merge_sort(arr, temp):
        if len(arr) <= 1:
            return arr, temp

        mid = len(arr) // 2
        left, temp = merge_sort(arr[:mid], temp)
        right, temp = merge_sort(arr[mid:], temp)

        return merge(left, right, temp)

    def merge(left, right, temp):
        i = j = k = 0
        inv_count = 0

        while i < len(left) and j < len(right):
            if left[i] <= right[j]:
                temp[k] = left[i]
                i += 1
            else:
                temp[k] = right[j]
                inv_count += len(left) - i
                j += 1
            k += 1

        while i < len(left):
            temp[k] = left[i]
            i += 1
            k += 1

        while j < len(right):
            temp[k] = right[j]
            j += 1
            k += 1

        return temp, inv_count

    _, inv_count = merge_sort(arr, [0] * len(arr))
    return inv_count

def get_Inv_Count(arr):
