        return None

    max_tuple = tuples_list[0]
    max_sum = max_tuple[1]

    for name, score in tuples_list:
        current_sum = score
        if name in max_tuple:
            current_sum += max_tuple[1]
            max_tuple = (name, current_sum)
            max_sum = current_sum
