                max_tuple = (name, current_sum)
                max_sum = current_sum

    return max_tuple

def max_aggregate(tuples):
    """
    Calculates the maximum aggregate from the list of tuples.
    The aggregate is the sum of the second element of the tuple for each unique first element.
    Returns the tuple with the first element being the name and the second element being the maximum aggregate.
    """
    max_name = None
    max_aggregate_value = float('-inf')

    for name, value in tuples:
        aggregate = 0
        for n, v in tuples:
            if n == name:
                aggregate += v
        if aggregate > max_aggregate_value:
            max_aggregate_value = aggregate
            max_name = name

    return (max_name, max_aggregate_value)

