def dict_depth_recursive(d, depth=1):
    if not isinstance(d, dict):
        return depth

    max_depth = depth
    for value in d.values():
        if isinstance(value, dict):
            max_depth = max(max_depth, dict_depth_recursive(value, depth + 1))

    return max_depth

def dict_depth_iterative(d):
    if not isinstance(d, dict):
        return 0

    current_depth = 1
    max_depth = 1

    def get_depth(current_dict, depth):
        nonlocal max_depth
        for value in current_dict.values():
            if isinstance(value, dict):
                max_depth = max(max_depth, depth + 1)
                get_depth(value, depth + 1)

    get_depth(d, 0)
    return max_depth

