def find_Element(arr, queries, rotations, index):
    if not arr or not queries:
        return None

    n = len(arr)
    if rotations == 0:
        for q in queries:
            if q[0] == index:
                return arr[q[1]]
        return None

    effective_rotations = rotations % n

    # Calculate the new index for each query
    for q in queries:
        start_idx, target_idx = q

        # If we need to rotate, adjust the target index
        if effective_rotations != 0:
            # The element at target_idx in the rotated array corresponds to:
            # (target_idx - effective_rotations) % n
            adjusted_target = (target_idx - effective_rotations) % n
            return arr[adjusted_target]

    return None

