def find_Element(arr, rotations, k, val):
    if not arr or not rotations:
        return -1

    n = len(arr)
    if k < 0 or k >= n:
        return -1

    # Apply rotations
    rotated_count = 0
    for r in rotations:
        if r[0] == 0:
            rotated_count += r[1]

    rotated_count = rotated_count % n
    rotated_arr = arr[-rotated_count:] + arr[:-rotated_count]

    # Find element at index k
    if 0 <= k < len(rotated_arr):
        return rotated_arr[k]
    else:
        return -1

