def max_sum_increasing_subseq(arr, n, i, k):
    if k > n or i >= n or k <= i:
        return 0

    # dp[j] will store the max sum of increasing subsequence ending at index j
    # considering only elements from index 0 to j
    dp = [0] * n

    for j in range(n):
        max_prev = 0
        for prev in range(j):
            if arr[prev] < arr[j]:
                max_prev = max(max_prev, dp[prev])
        dp[j] = max_prev + arr[j]

    # Find max sum in dp[0...i]
    max_before_i = 0
    for j in range(i + 1):
        max_before_i = max(max_before_i, dp[j])

    # Calculate max sum including arr[k]
    # We need to find max(dp[j]) where j <= i and arr[j] < arr[k]
    max_before_k = 0
    for j in range(i + 1):
        if arr[j] < arr[k]:
            max_before_k = max(max_before_k, dp[j])

    result = max_before_k + arr[k]

    return max(max_before_i, result)

