def max_sum_increasing_subseq(arr, n, i, k):
    if i >= k or k >= n:
        return 0
    if i < 0 or k < 0:
        return 0

    dp = [0] * n

    for idx in range(n):
        max_prev = 0
        for prev_idx in range(idx):
            if arr[prev_idx] < arr[idx]:
                max_prev = max(max_prev, dp[prev_idx])
        dp[idx] = max_prev + arr[idx]

    result = 0
    for idx in range(i + 1, k + 1):
        if dp[idx] > result:
            result = dp[idx]

    return result

def max_sum_increasing_subseq(arr, n, i, k):
    if k > n or i < 0 or k < 0 or i >= n or k >= n:
        return 0

    if i >= k:
        return 0

    dp = [0] * n
    dp[i] = arr[i]

    for j in range(i + 1, k + 1):
        if arr[j] > arr[i]:
            dp[j] = arr[j] + dp[i]
        else:
            dp[j] = arr[j]

    for j in range(i + 1, k + 1):
        for p in range(i, j):
            if arr[j] > arr[p]:
                dp[j] = max(dp[j], dp[p] + arr[j])

    return max(dp[i:k+1])

