def colon_tuplex(tup, idx, val):
    if idx < 0 or idx >= len(tup):
        raise IndexError("Index out of bounds")
    new_list = list(tup)
    if isinstance(new_list[idx], list):
        new_list[idx].append(val)
    else:
        new_list[idx] = [val]
    return tuple(new_list)

def colon_tuplex(tup, idx, val):
    """
    Replaces the element at index `idx` in the tuple `tup` with a list containing `val`.
    Note: Tuples are immutable, so we return a new tuple.
    """
    if idx < 0 or idx >= len(tup):
        raise IndexError("Index out of range")

    new_list = list(tup)
    new_list[idx] = [val]
    return tuple(new_list)

def colon_tuplex(tup, start, end):
    result = list(tup)
    if start < len(result) and end < len(result):
        result[start:end] = [end]
    return tuple(result)

def colon_tuplex(tup, start, end):
    if not isinstance(tup, tuple):
        raise TypeError("First argument must be a tuple")
    if not isinstance(start, int) or not isinstance(end, int):
        raise TypeError("start and end must be integers")
    if start < 0 or end < 0:
        raise ValueError("start and end must be non-negative")
    if start > end:
        raise ValueError("start must be less than or equal to end")
    if start > len(tup):
        raise IndexError("start is out of bounds")
    if end > len(tup):
        raise IndexError("end is out of bounds")

    result = []
    for i in range(start, end + 1):
        item = tup[i]
        if isinstance(item, list):
            result.append(item + [end])
        else:
            result.append(item)
    return tuple(result)

