def set_left_most_unset_bit(n):
    # Convert n to binary string, strip '0b'
    binary = bin(n)[2:]
    length = len(binary)

    # Find the leftmost position that is '0'
    for i in range(length - 1, -1, -1):
        if binary[i] == '0':
            # Set this bit to '1'
            binary = binary[:i] + '1' + binary[i+1:]
            return int(binary, 2)

    # If all bits are 1, we need to add a new bit at the front
    return int('1' + binary, 2)

# Test
assert set_left_most_unset_bit(10) == 14

def set_left_most_unset_bit(n):
    # Find the position of the leftmost unset bit
    # Iterate from bit 0 upwards
    bit_position = 0
    while (n & (1 << bit_position)):
        bit_position += 1

    # Set the bit at that position
    return n | (1 << bit_position)

# Test
assert set_left_most_unset_bit(10) == 14

