def rearrange_bigger(n):
    s = list(str(n))
    if len(s) <= 1:
        return n

    # Try to find the next permutation
    i = len(s) - 2
    while i >= 0 and s[i] >= s[i+1]:
        i -= 1

    if i < 0:
        return n  # No bigger number possible (descending order)

    j = len(s) - 1
    while s[j] <= s[i]:
        j -= 1

    s[i], s[j] = s[j], s[i]

    # Reverse the suffix
    s[i+1:] = s[i+1:][::-1]

    return int("".join(s))

def rearrange_bigger(n):
    if n < 10:
        return None

    digits = list(str(n))
    digits.sort(reverse=True)

    if digits[0] == '1' and len(digits) == 2:
        return 12 if n == 1 else None

    pivot_index = len(digits) - 1
    while pivot_index > 0 and digits[pivot_index] <= '1':
        pivot_index -= 1

    if pivot_index == 0:
        return None

    digits[pivot_index], digits[-1] = digits[-1], digits[pivot_index]
    digits[-1] = '1'

    for i in range(len(digits) - 1, 0, -1):
        if digits[i] > '1':
            digits[i], digits[-1] = digits[-1], digits[i]
            break

    result = int("".join(digits))
    return result if result > n else None

def test_rearrange_bigger():
    assert rearrange_bigger(12) == 21
