    if not nums1 or not nums2 or k <= 0:
        return []

    # Min-heap to store tuples of (sum, index_in_nums1, index_in_nums2)
    min_heap = []

    # Initialize the heap with the first element from each array
    for i in range(min(len(nums1), k)):
        if i < len(nums1) and i < len(nums2):
            heapq.heappush(min_heap, (nums1[i] + nums2[0], i, 0))

    result = []

    while min_heap and len(result) < k:
        current_sum, i, j = heapq.heappop(min_heap)
        result.append([nums1[i], nums2[j]])

        # Push the next element from nums2 for the current element from nums1
        if j + 1 < len(nums2):
            heapq.heappush(min_heap, (nums1[i] + nums2[j + 1], i, j + 1))

    return result

import heapq

def k_smallest_pairs(nums1, nums2, k):
    if not nums1 or not nums2 or k <= 0:
        return []

    # Min-heap to store tuples (sum, index_in_nums1, index_in_nums2)
    # We use a counter to break ties consistently
    heap = []
    for i in range(len(nums1)):
        for j in range(len(nums2)):
            heapq.heappush(heap, (nums1[i] + nums2[j], i, j))

    result = []
    while k > 0 and heap:
        _, i, j = heapq.heappop(heap)
        result.append([nums1[i], nums2[j]])
        k -= 1

    return result

