def k_smallest_pairs(nums1, nums2, k):
    if not nums1 or not nums2 or k <= 0:
        return []

    min_heap = []
    # Initialize the heap with the first element from each array
    for i in range(min(len(nums1), k)):
        if i < len(nums1) and i < len(nums2):
            heapq.heappush(min_heap, (nums1[i], nums2[i], i, 0))

    result = []
    while min_heap and k > 0:
        val1, val2, i, j = heapq.heappop(min_heap)
        result.append([val1, val2])
        k -= 1
        if j + 1 < len(nums2):
            heapq.heappush(min_heap, (val1, nums2[j + 1], i, j + 1))

    return result

