def snake_to_camel(snake_case_string):
    if not snake_case_string:
        return ""

    # Convert first character to uppercase and rest to camel case
    camel_case_string = snake_case_string[0].upper()
    for char in snake_case_string[1:]:
        if char == '_':
            continue
        else:
            camel_case_string += char.capitalize()

    return camel_case_string

