def group_tuples(tuples):
    from collections import defaultdict

    groups = defaultdict(list)
    for t in tuples:
        if len(t) == 2:
            groups[t[0]].append(t[1])
        else:
            groups[t[0]].append(t)

    result = []
    for key in sorted(groups.keys()):
        if len(groups[key]) == 1:
            result.append((key, groups[key][0]))
        else:
            result.append((key, tuple(sorted(groups[key]))))

    return result

def group_tuples(tuples):
    from collections import defaultdict

    groups = defaultdict(set)
    for t in tuples:
        if t:  # Ensure tuple is not empty
            groups[t[0]].add(t[1])

    result = []
    for key in sorted(groups.keys()):
        if len(groups[key]) > 0:
            result.append((key, *groups[key]))
    return result

