def group_tuples(tuples):
    if not tuples:
        return []

    first_elements = defaultdict(list)
    for t in tuples:
        if len(t) >= 1:
            first_elements[t[0]].append(t)

    groups = []
    for first, items in first_elements.items():
        if len(items) > 1:
            other_elements = [t[1] for t in items if len(t) > 1]
            groups.append((first, *other_elements))
        else:
            groups.append(items[0])

    return groups

