def change_date_format(date_str: str) -> str:
    """
    Converts a date string from 'yyyy-mm-dd' format to 'dd-mm-yyyy' format.

    Args:
        date_str (str): A date string in 'yyyy-mm-dd' format.

    Returns:
        str: The date string in 'dd-mm-yyyy' format.

    Raises:
        ValueError: If the input string is not in the expected format or represents an invalid date.
    """
    parts = date_str.split('-')

    if len(parts) != 3:
        raise ValueError("Input must be in 'yyyy-mm-dd' format.")

    try:
        year = int(parts[0])
        month = int(parts[1])
        day = int(parts[2])
    except ValueError:
        raise ValueError("Input string must contain only digits in the date parts.")

    # Basic validation for month and day ranges
    if not (1 <= month <= 12):
        raise ValueError(f"Invalid month: {month}")
    if not (1 <= day <= 31):
        raise ValueError(f"Invalid day: {day}")

    # More precise day validation based on month and year
    if month in [4, 6, 9, 11]:
        if day > 30:
            raise ValueError(f"Invalid day for month {month}")
    elif month == 2:
        is_leap = (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0)
        if day > 29 or (is_leap and day > 28):
            raise ValueError(f"Invalid day for month {month} in year {year}")

