def sumofFactors(n):
    if n <= 0:
        return 0

    sum_even = 0
    i = 2
    while i * i <= n:
        if n % i == 0:
            factor = i
            if factor % 2 == 0:
                sum_even += factor
            other_factor = n // factor
            if other_factor != factor:
                if other_factor % 2 == 0:
                    sum_even += other_factor
        i += 1

    if n % 2 == 0:
        sum_even += n

    return sum_even

