        return 0

    total = 0
    i = 2
    while i * i <= n:
        if n % i == 0:
            factor1 = i
            factor2 = n // i

            if factor1 % 2 == 0:
                total += factor1

            if factor1 != factor2 and factor2 % 2 == 0:
                total += factor2
        i += 1

    if n % 2 == 0:
        total += n

    return total

