def sumofFactors(n):
    if n < 0:
        return 0
    if n == 0:
        return 0

    factors = []
    i = 1
    while i * i <= n:
        if n % i == 0:
            factors.append(i)
            if i != n // i:
                factors.append(n // i)
        i += 1

    return sum(f for f in factors if f % 2 == 0)

