def combinations(iterable, r):
    if r == 0:
        yield []
        return
    if r == 1:
        for item in iterable:
            yield [item]
        return

    first = next(iter(iterable))
    rest = combinations(list(iterable), r)
    for item in rest:
        yield [first] + item

    for item in combinations(list(iterable), r - 1):
        yield item

