def combinations_list(lst):
    def helper(index, current_combination):
        if index == len(lst):
            return [current_combination[:]]

        results = []
        # Include the element at current index
        current_combination.append(lst[index])
        results.extend(helper(index + 1, current_combination))

        # Exclude the element at current index
        current_combination.pop()
        results.extend(helper(index + 1, current_combination))

        return results

    return helper(0, [])

